#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    int max_ones = 0;
    int current_ones = 0;
    for(int num : nums) {
        if(num == 1) {
            current_ones += 1;
            max_ones = max(max_ones, current_ones);
        } else {
            current_ones = 0;
        }
    }
    cout << max_ones;
}
